let MONTHS = ["Janvier", "Février", "Mars", "Avril", "Mai", "Juin", "Juillet", "Août", "Septembre", "Octobre", "Novembre", "Décembre"]
fn monthName(m) {
  let i = floor(m) - 1
  if (i < 0) {
    return "?"
  }
  if (i > 11) {
    return "?"
  }
  return MONTHS[i]
}
fn addMonths(m, y, delta) {
  let total = y * 12 + (m - 1) + delta
  let ny = floor(total / 12)
  let nm = total - ny * 12 + 1
  return { m: nm, y: ny }
}
fn intDigits(d) {
  let parts = split(toString(d), ".")
  return parts[0]
}
fn groupDigits(ds) {
  let n = length(ds)
  if (n <= 3) {
    return ds
  }
  let out = ""
  let i = 0
  while (i < n) {
    if (i > 0) {
      if ((n - i) % 3 == 0) {
        out = out + " "
      }
    }
    out = out + substring(ds, i, i + 1)
    i = i + 1
  }
  return out
}
fn money(n) {
  let neg = false
  let v = n
  if (v < 0) {
    neg = true
    v = -v
  }
  let cents = round(v * 100)
  let whole = floor(cents / 100)
  let frac = cents - whole * 100
  let fracStr = intDigits(frac)
  if (frac < 10) {
    fracStr = "0" + fracStr
  }
  let s = groupDigits(intDigits(whole)) + "," + fracStr + " €"
  if (neg) {
    s = "-" + s
  }
  return s
}
fn numToInput(n) {
  let parts = split(toString(n), ".")
  if (parts.length < 2) {
    return parts[0]
  }
  if (parts[1] == "0") {
    return parts[0]
  }
  return parts[0] + "." + parts[1]
}
fn pctInt(part, whole) {
  if (whole <= 0) {
    return 0
  }
  let p = floor(part * 100 / whole)
  if (p < 0) {
    return 0
  }
  if (p > 100) {
    return 100
  }
  return p
}
