  return Box({ color: trackColor, borderRadius: heightPx }, Row({}, [Expanded({ flex: fill }, Box({ color: fillColor, borderRadius: heightPx, height: heightPx })), Expanded({ flex: rest }, Box({ height: heightPx }))]))
}
