fn matchesQuery(t) {
  let q = query.value
  if (q == "") {
    return true
  }
  let ql = toLowerCase(q)
  let cat = categoryByKey(t.category)
  if (contains(toLowerCase(cat.label), ql)) {
    return true
  }
  if (contains(toLowerCase(t.note), ql)) {
    return true
  }
  return false
}
fn visibleTx(f) {
  let q = query.value
  let cf = catFilter.value
  monthOffset.value
  let p = periodMY()
  let inMonth = monthItemsFor(tx.value, p.m, p.y)
  let all = reverse(inMonth)
  let out = []
  all.forEach(fn(t, i) {
    let ok = true
    if (f == "income") {
      if (t.type != "income") {
        ok = false
      }
    }
    if (f == "expense") {
      if (t.type != "expense") {
        ok = false
      }
    }
    if (cf != "all") {
      if (t.category != cf) {
        ok = false
      }
    }
    if (ok) {
      if (matchesQuery(t) == false) {
        ok = false
      }
    }
    if (ok) {
      out.add(t)
    }
  })
  return out
}
