}
fn monthNav(p) {
  return Row({ crossAxisAlignment: "center" }, [navBtn("chevron_left", "prevMonth"), Expanded({ flex: 1 }, Center(Text(monthName(p.m) + " " + intDigits(p.y), { fontSize: 15, fontWeight: "600", color: T.onPrimary }))), navBtn("chevron_right", "nextMonth")])
}
fn navBtn(icon, cb) {
  return InkWell({ onTap: cb, borderRadius: 16 }, Box({ padding: 6, borderRadius: 16 }, Icon(icon, { size: 22, color: T.onPrimary })))
}
fn flowPill(label, value, accent) {
  return Box({ color: alpha(T.onPrimary, "1F"), borderRadius: 12, padding: 10 }, Column({ crossAxisAlignment: "start", spacing: 2 }, [Row({ spacing: 6, crossAxisAlignment: "center" }, [dot(accent, 8), Text(label, { fontSize: 11, color: alpha(T.onPrimary, "CC") })]), Text(value, { fontSize: 15, fontWeight: "bold", color: T.onPrimary })]))
