fn budgetBlock(spent) {
  let b = loadBudget()
  if (b <= 0) {
    return InkWell({ onTap: "openBudget", borderRadius: 12 }, Box({ color: alpha(T.onPrimary, "1F"), borderRadius: 12, padding: 10 }, Row({ spacing: 8, crossAxisAlignment: "center" }, [Icon("add", { size: 18, color: T.onPrimary }), Text("Définir un budget mensuel", { fontSize: 13, fontWeight: "600", color: T.onPrimary })])))
  }
  let pct = pctInt(spent, b)
  let over = spent > b
  let fillColor = T.onPrimary
  let restLabel = "Reste " + money(b - spent)
