fn listIncome() {
  return txList("income")
}
fn listExpense() {
  return txList("expense")
}
fn txList(f) {
  let items = visibleTx(f)
  if (items.length == 0) {
    return emptyState()
  }
  let rows = items.map(fn(t) {
    return txRow(t)
  })
  return ScrollView({ padding: 16 }, Column({ spacing: 10 }, rows))
}
fn txRow(t) {
  let cat = categoryByKey(t.category)
