  return InkWell({ onTap: "onOpen", arg: t.id, borderRadius: 16 }, Box({
    color: T.surface,
    borderRadius: 16,
    padding: 12,
    borderColor: T.line,
    borderWidth: 1
  }, Row({ crossAxisAlignment: "center", spacing: 12 }, [catAvatar(cat, 44), Expanded({ flex: 1 }, Column({ crossAxisAlignment: "start", spacing: 3 }, [Text(cat.label, { fontSize: 15, fontWeight: "600", color: T.text }), Text(rowSubtitle(t), { fontSize: 12, color: T.muted })])), Text(sign + money(t.amount), { fontSize: 15, fontWeight: "bold", color: amountColor })])))
