fn rowSubtitle(t) {
  let d = formatDate(t.date, "DD/MM/YYYY")
  if (t.note == "") {
    return d
  }
  return d + " · " + t.note
}
fn emptyState() {
  return Center(Column({ crossAxisAlignment: "center", mainAxisAlignment: "center", spacing: 10 }, [Text("💸", { fontSize: 56 }), Text("Aucune transaction", { fontSize: 18, fontWeight: "600", color: T.muted }), Text("Ajoutez-en une ou changez de mois", { fontSize: 13, color: T.muted })]))
