fn budgetModal() {
  return Box({ color: T.surface, borderRadius: 18, padding: 20 }, Column({ crossAxisAlignment: "start", spacing: 14, mainAxisSize: "min" }, [Text("Budget mensuel", { fontSize: 17, fontWeight: "bold", color: T.text }), Text("Plafond de dépenses pour le mois.", { fontSize: 13, color: T.muted }), TextField({
    labelText: "Montant (€)",
    value: budgetDraft,
    onChange: "onBudgetInput",
    keyboardType: "number",
    prefixIcon: "payment"
  }), Row({ spacing: 10 }, [Expanded({ flex: 1 }, Button("Annuler", {
    onTap: "closeModal",
    variant: "text",
    color: T.muted,
    fullWidth: true
  })), Expanded({ flex: 1 }, Button("Enregistrer", { onTap: "saveBudgetVal", color: T.primary, fullWidth: true }))]), clearBudgetBtn()]))
}
fn clearBudgetBtn() {
  if (loadBudget() <= 0) {
    return Box({})
  }
  return Button("Supprimer le budget", {
    onTap: "clearBudget",
    variant: "text",
    color: T.danger,
    fullWidth: true
  })
}

