  let out = []
  while (items.length > 0) {
    let bestIdx = 0
    let best = items[0]
    let i = 1
    while (i < items.length) {
      if (items[i].total > best.total) {
        best = items[i]
        bestIdx = i
      }
      i = i + 1
    }
    out.add(best)
    let rest = []
    let j = 0
    while (j < items.length) {
      if (j != bestIdx) {
        rest.add(items[j])
      }
      j = j + 1
    }
    items = rest
  }
  return out
}
